// src/pages/DashboardPage.jsx
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import UserCard from '../components/shared/UserCard';
import { BtnPrimary, BtnGhost, StatusBadge, Spinner } from '../components/shared/UI';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

const StatCard = ({ icon, label, value, color }) => (
  <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:24, textAlign:'center' }}>
    <div style={{ fontSize:28, marginBottom:8 }}>{icon}</div>
    <div style={{ fontFamily:'Clash Display, sans-serif', fontSize:36, fontWeight:700, color }}>{value}</div>
    <div style={{ color:'var(--muted)', fontSize:13, marginTop:4 }}>{label}</div>
  </div>
);

export default function DashboardPage() {
  const { user } = useAuth();
  const [exchanges, setExchanges]       = useState([]);
  const [matches, setMatches]           = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading]           = useState(true);

  useEffect(() => {
    (async () => {
      try {
        const [ex, ma, no] = await Promise.all([
          api.get('/exchanges'),
          api.get('/users/matches'),
          api.get('/messages/notifications'),
        ]);
        setExchanges(ex.data.exchanges || []);
        setMatches(ma.data.matches || []);
        setNotifications(no.data.notifications || []);
      } catch {}
      finally { setLoading(false); }
    })();
  }, []);

  const active    = exchanges.filter(e => e.status === 'accepted');
  const pending   = exchanges.filter(e => e.status === 'pending');
  const completed = exchanges.filter(e => e.status === 'completed');
  const unread    = notifications.filter(n => !n.is_read);
  const profileOk = user?.skills_offered?.length > 0 && user?.skills_wanted?.length > 0;

  return (
    <div style={{ minHeight:'100vh', paddingTop:80, position:'relative', zIndex:1 }}>
      <Navbar />
      <div style={{ maxWidth:1200, margin:'0 auto', padding:'40px 24px' }}>

        {/* Hero Banner */}
        <div style={{ borderRadius:20, padding:'40px 48px', marginBottom:40, background:'linear-gradient(135deg,rgba(108,99,255,.15),rgba(255,107,107,.08))', border:'1px solid rgba(108,99,255,.2)', position:'relative', overflow:'hidden' }}>
          <div style={{ position:'absolute', top:-60, right:-60, width:200, height:200, borderRadius:'50%', background:'rgba(108,99,255,.06)', pointerEvents:'none' }} />
          <div style={{ position:'relative' }}>
            <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:14 }}>
              <span style={{ width:8, height:8, borderRadius:'50%', background:'var(--accent3)', display:'inline-block' }} />
              <span style={{ fontSize:13, color:'var(--accent3)', fontWeight:500 }}>Live Platform — Active Now</span>
            </div>
            <h1 style={{ fontFamily:'Clash Display, sans-serif', fontSize:'clamp(26px,4vw,46px)', fontWeight:700, lineHeight:1.1, marginBottom:10 }}>
              Hey, {user?.name?.split(' ')[0]}! 👋
              <br />
              <span style={{ background:'linear-gradient(135deg,var(--accent),var(--accent2),var(--accent3))', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>
                {matches.length > 0 ? `${matches.length} skill match${matches.length > 1 ? 'es' : ''} waiting` : 'Start matching with experts'}
              </span>
            </h1>
            <p style={{ color:'var(--muted)', fontSize:15, marginBottom:24 }}>Trade skills, grow together. Every exchange builds your reputation.</p>
            <div style={{ display:'flex', gap:12, flexWrap:'wrap' }}>
              <Link to="/search"><BtnPrimary style={{ fontSize:15, padding:'12px 28px' }}>🔍 Find Skills</BtnPrimary></Link>
              {!profileOk && <Link to="/profile/edit"><BtnGhost style={{ fontSize:15, padding:'12px 28px' }}>✏️ Complete Profile</BtnGhost></Link>}
            </div>
          </div>
        </div>

        {/* Profile nudge */}
        {!profileOk && (
          <div style={{ marginBottom:28, padding:16, borderRadius:12, background:'rgba(255,215,0,.05)', border:'1px solid rgba(255,215,0,.18)', display:'flex', alignItems:'center', justifyContent:'space-between', gap:12 }}>
            <div style={{ display:'flex', gap:12, alignItems:'center' }}>
              <span style={{ fontSize:22 }}>⚠️</span>
              <div>
                <div style={{ fontWeight:600, color:'#ffd700', fontSize:14 }}>Complete your profile</div>
                <div style={{ color:'var(--muted)', fontSize:12, marginTop:2 }}>Add skills to teach & learn to unlock matches!</div>
              </div>
            </div>
            <Link to="/profile/edit">
              <button style={{ padding:'8px 20px', borderRadius:8, background:'linear-gradient(135deg,#ffd700,#ffaa00)', color:'#1a1100', fontWeight:700, fontSize:13, border:'none', cursor:'pointer', whiteSpace:'nowrap' }}>Set up →</button>
            </Link>
          </div>
        )}

        {/* Stats Grid */}
        <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:16, marginBottom:40 }}>
          <StatCard icon="🤝" label="Active Exchanges" value={active.length}    color="var(--accent)" />
          <StatCard icon="⏳" label="Pending Requests" value={pending.length}   color="#ffaa00" />
          <StatCard icon="✅" label="Completed"        value={completed.length} color="var(--accent3)" />
          <StatCard icon="🔔" label="Unread Alerts"    value={unread.length}    color="var(--accent2)" />
        </div>

        {/* Main Grid */}
        <div style={{ display:'grid', gridTemplateColumns:'1fr 2fr', gap:32 }}>

          {/* Left Column */}
          <div style={{ display:'flex', flexDirection:'column', gap:24 }}>

            {/* Recent Exchanges */}
            <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:24 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:18 }}>
                <h3 style={{ fontFamily:'Clash Display, sans-serif', fontSize:18, fontWeight:700 }}>Recent Exchanges</h3>
                <Link to="/exchanges" style={{ color:'var(--accent)', fontSize:13, textDecoration:'none' }}>All →</Link>
              </div>
              {loading ? <div style={{ display:'flex', justifyContent:'center', padding:24 }}><Spinner /></div>
                : exchanges.length === 0 ? (
                  <div style={{ textAlign:'center', padding:'16px 0', color:'var(--muted)' }}>
                    <div style={{ fontSize:28, marginBottom:6 }}>🤝</div>
                    <p style={{ fontSize:13 }}>No exchanges yet</p>
                  </div>
                ) : (
                  <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
                    {exchanges.slice(0, 5).map(ex => {
                      const isReq = ex.requester_id === user?.id;
                      const other = isReq ? ex.provider_name : ex.requester_name;
                      return (
                        <Link key={ex.id} to={`/exchanges/${ex.id}`} style={{ textDecoration:'none', display:'flex', alignItems:'center', gap:10, padding:'10px', borderRadius:10, transition:'background .2s' }}
                          onMouseOver={e => e.currentTarget.style.background='var(--surface2)'}
                          onMouseOut={e => e.currentTarget.style.background='transparent'}>
                          <div style={{ width:34, height:34, borderRadius:'50%', background:'linear-gradient(135deg,var(--accent),var(--accent2))', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, fontSize:13, color:'white', flexShrink:0, fontFamily:'Clash Display' }}>
                            {other?.charAt(0)?.toUpperCase()}
                          </div>
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ fontWeight:600, fontSize:13, color:'var(--text)', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{other}</div>
                            <div style={{ fontSize:11, color:'var(--muted)' }}>{isReq ? ex.provider_skill_name : ex.requester_skill_name}</div>
                          </div>
                          <StatusBadge status={ex.status} />
                        </Link>
                      );
                    })}
                  </div>
                )
              }
            </div>

            {/* Notifications */}
            <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:24 }}>
              <h3 style={{ fontFamily:'Clash Display, sans-serif', fontSize:18, fontWeight:700, marginBottom:16 }}>🔔 Notifications</h3>
              {notifications.length === 0
                ? <p style={{ color:'var(--muted)', fontSize:13, textAlign:'center' }}>No notifications yet</p>
                : <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
                    {notifications.slice(0, 5).map(n => (
                      <div key={n.id} style={{ padding:'10px 12px', borderRadius:10, background: n.is_read ? 'transparent' : 'rgba(108,99,255,.07)', border:`1px solid ${n.is_read ? 'transparent' : 'rgba(108,99,255,.2)'}` }}>
                        <div style={{ fontWeight:600, fontSize:13 }}>{n.title}</div>
                        <div style={{ color:'var(--muted)', fontSize:12, marginTop:2 }}>{n.body}</div>
                      </div>
                    ))}
                  </div>
              }
            </div>
          </div>

          {/* Right: Matches */}
          <div>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:20 }}>
              <h3 style={{ fontFamily:'Clash Display, sans-serif', fontSize:22, fontWeight:700 }}>🎯 Your Skill Matches</h3>
              <Link to="/search" style={{ color:'var(--accent)', fontSize:13, textDecoration:'none' }}>Browse all →</Link>
            </div>
            {loading
              ? <div style={{ display:'flex', justifyContent:'center', padding:64 }}><Spinner size={48} /></div>
              : matches.length === 0
                ? <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:'64px 32px', textAlign:'center' }}>
                    <div style={{ fontSize:48, marginBottom:16 }}>🎯</div>
                    <h3 style={{ fontFamily:'Clash Display, sans-serif', fontSize:22, marginBottom:8 }}>No matches yet</h3>
                    <p style={{ color:'var(--muted)', fontSize:14, marginBottom:24 }}>Add skills you teach and want to learn to get matched!</p>
                    <Link to="/profile/edit"><BtnPrimary>Add Your Skills</BtnPrimary></Link>
                  </div>
                : <div style={{ display:'grid', gridTemplateColumns:'repeat(2,1fr)', gap:20 }}>
                    {matches.slice(0, 4).map(u => <UserCard key={u.id} user={u} />)}
                  </div>
            }
          </div>
        </div>
      </div>
    </div>
  );
}
